import{_ as a,o as t,c as e,ae as s}from"./chunks/framework.D0EcU_Ug.js";const c="/linux-docs/assets/fastfetch-arch.SSSiiHpw.png",r="/linux-docs/assets/fastfetch-cachyos.DASe2YFZ.png",o="/linux-docs/assets/fastfetch-nixos.DqG9uzjR.png",_=JSON.parse('{"title":"写在前面：从 Arch 折腾到 NixOS","description":"","frontmatter":{},"headers":[],"relativePath":"notes/preface.md","filePath":"notes/preface.md"}'),l={name:"notes/preface.md"};function n(h,i,p,f,d,x){return t(),e("div",null,[...i[0]||(i[0]=[s('<h1 id="写在前面-从-arch-折腾到-nixos" tabindex="-1">写在前面：从 Arch 折腾到 NixOS <a class="header-anchor" href="#写在前面-从-arch-折腾到-nixos" aria-label="Permalink to &quot;写在前面：从 Arch 折腾到 NixOS&quot;">​</a></h1><p>这个站最早只是拿来记命令和坑点的。用久了才发现，真正会留下来的不是“今天装了什么”，而是那些把系统折腾坏之后又一点点修回来的过程。</p><p>过去几个月，我在发行版之间来回跑了好几趟：</p><ul><li>Arch Linux</li><li>CachyOS</li><li>回到 Arch Linux</li><li>现在是 NixOS</li></ul><p>重装、迁移、换桌面环境、修引导、调显卡、救网络，很多事情都不止做过一遍。折腾多了以后，人会慢慢变得现实一点，不再追求“最酷的桌面截图”，而是更在意一台机器能不能稳定地被重新搭起来。</p><div class="shot-grid"><figure class="shot-card"><img src="'+c+'" alt="Arch fastfetch"><figcaption>Arch</figcaption></figure><figure class="shot-card"><img src="'+r+'" alt="CachyOS fastfetch"><figcaption>CachyOS</figcaption></figure><figure class="shot-card"><img src="'+o+'" alt="NixOS fastfetch"><figcaption>NixOS</figcaption></figure></div><h2 id="为什么最后落到-nixos" tabindex="-1">为什么最后落到 NixOS <a class="header-anchor" href="#为什么最后落到-nixos" aria-label="Permalink to &quot;为什么最后落到 NixOS&quot;">​</a></h2><p>不是因为它更神，也不是因为它更难。</p><p>只是前面折腾到后来，我越来越想把这些东西收起来：</p><ul><li>系统到底装了什么</li><li>为什么要这样配</li><li>改坏以后怎么退回去</li><li>重装以后怎样最快恢复</li></ul><p>Arch 和 CachyOS 让我学会了不少硬碰硬的东西。NixOS 则更像是把这些经验装进文件里。它不一定更省时间，但更少靠记忆。</p><h2 id="这个站现在怎么读" tabindex="-1">这个站现在怎么读 <a class="header-anchor" href="#这个站现在怎么读" aria-label="Permalink to &quot;这个站现在怎么读&quot;">​</a></h2><p>如果你是第一次打开这里，最好的顺序不是从头翻到尾，而是按分类进：</p><ol><li>先看 <a href="/linux-docs/notes/">目录</a></li><li>碰到什么问题，就进对应那一栏</li><li>想看我最近在折腾什么，再回来看 <a href="/linux-docs/notes/nix/">NixOS / Nix</a></li></ol><p>我把原来那几篇很长的文章拆掉了。现在每个问题一篇，目录也重新分过类，查起来应该顺手很多。</p>',15)])])}const S=a(l,[["render",n]]);export{_ as __pageData,S as default};
